using namespace std;

class Solution {
public:
    // Method to find the minimum number of servers needed to connect server 1 to server n
    int getMinimumServers(int n, vector<pair<int, int>> serverConnections) {
        // Number of connections (edges)
        int m = serverConnections.size();

        // Initialize distance array with a large number
        vector<int> distance(n + 1, 1e9);

        // Create an adjacency list for the graph
        vector<int> graph[n + 1];
        for (auto& connection : serverConnections) {
            int a = connection.first;
            int b = connection.second;
            graph[a].push_back(b);
            graph[b].push_back(a);
        }

        // BFS setup
        queue<int> q;
        q.push(1); // Start from server 1
        distance[1] = 0; // Distance to itself is 0

        // Array to track parent nodes (not used in this simple version)
        vector<int> parent(n + 1, -1);

        // Perform BFS to find the shortest path
        while (!q.empty()) {
            int v = q.front();
            q.pop();

            // If we reached server n, return the distance
            if (v == n) break;

            // Check all adjacent servers
            for (int neighbor : graph[v]) {
                // If visiting this neighbor is better, update its distance and enqueue it
                if (1 + distance[v] < distance[neighbor]) {
                    distance[neighbor] = 1 + distance[v];
                    parent[neighbor] = v; // Track the path (not used here)
                    q.push(neighbor);
                }
            }
        }

        // If we can't reach server n, return -1
        if (distance[n] == 1e9)
            return -1;

        // Return the minimum number of servers needed
        return 1 + distance[n];
    }
};

