#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <limits.h>

#define INF INT_MAX

// Queue structure for BFS
typedef struct {
    int *data;
    int front, rear, size, capacity;
} Queue;

// Initialize a queue
Queue* createQueue(int capacity) {
    Queue *q = (Queue*)malloc(sizeof(Queue));
    q->data = (int*)malloc(capacity * sizeof(int));
    q->front = 0;
    q->rear = -1;
    q->size = 0;
    q->capacity = capacity;
    return q;
}

// Enqueue operation
void enqueue(Queue *q, int item) {
    q->rear = (q->rear + 1) % q->capacity;
    q->data[q->rear] = item;
    q->size++;
}

// Dequeue operation
int dequeue(Queue *q) {
    int item = q->data[q->front];
    q->front = (q->front + 1) % q->capacity;
    q->size--;
    return item;
}

// Check if the queue is empty
bool isEmpty(Queue *q) {
    return q->size == 0;
}

// Free the queue memory
void freeQueue(Queue *q) {
    free(q->data);
    free(q);
}

// Method to find the minimum number of servers needed to connect server 1 to server n
int getMinimumServers(int n, int m, int edges[][2]) {
    int distance[n + 1];
    int **graph = (int**)malloc((n + 1) * sizeof(int*));
    int *graphSize = (int*)malloc((n + 1) * sizeof(int));

    // Initialize distance array and adjacency list
    for (int i = 1; i <= n; i++) {
        distance[i] = INF;
        graph[i] = (int*)malloc(n * sizeof(int));
        graphSize[i] = 0;
    }

    // Create the graph from edges
    for (int i = 0; i < m; i++) {
        int a = edges[i][0];
        int b = edges[i][1];
        graph[a][graphSize[a]++] = b;
        graph[b][graphSize[b]++] = a;
    }

    // BFS setup
    Queue *q = createQueue(n + 1);
    enqueue(q, 1); // Start from server 1
    distance[1] = 0;

    // Perform BFS to find the shortest path
    while (!isEmpty(q)) {
        int v = dequeue(q);

        // If we reached server n, return the distance
        if (v == n) {
            freeQueue(q);
            for (int i = 1; i <= n; i++) {
                free(graph[i]);
            }
            free(graph);
            free(graphSize);
            return 1 + distance[n];
        }

        // Check all adjacent servers
        for (int i = 0; i < graphSize[v]; i++) {
            int neighbor = graph[v][i];
            // If visiting this neighbor is better, update its distance and enqueue it
            if (1 + distance[v] < distance[neighbor]) {
                distance[neighbor] = 1 + distance[v];
                enqueue(q, neighbor);
            }
        }
    }

    // If we can't reach server n, return -1
    freeQueue(q);
    for (int i = 1; i <= n; i++) {
        free(graph[i]);
    }
    free(graph);
    free(graphSize);
    return -1;
}

