        int m = serverConnections.size();

        // Initialize distance array with a large number
        int[] distance = new int[n + 1];
        Arrays.fill(distance, Integer.MAX_VALUE);

        // Create an adjacency list for the graph
        List<Integer>[] graph = new ArrayList[n + 1];
        for (int i = 1; i <= n; i++) {
            graph[i] = new ArrayList<>();
        }

        for (int[] connection : serverConnections) {
            int a = connection[0];
            int b = connection[1];
            graph[a].add(b);
            graph[b].add(a);
        }

        // BFS setup
        Queue<Integer> q = new LinkedList<>();
        q.add(1); // Start from server 1
        distance[1] = 0; // Distance to itself is 0

        // Perform BFS to find the shortest path
        while (!q.isEmpty()) {
            int v = q.poll();

            // If we reached server n, return the distance
            if (v == n) break;

            // Check all adjacent servers
            for (int neighbor : graph[v]) {
                // If visiting this neighbor is better, update its distance and enqueue it
                if (1 + distance[v] < distance[neighbor]) {
                    distance[neighbor] = 1 + distance[v];
                    q.add(neighbor);
                }
            }
        }

        // If we can't reach server n, return -1
        if (distance[n] == Integer.MAX_VALUE)
            return -1;

        // Return the minimum number of servers needed
