const readline = require('readline');

// Function to find the shortest path from node 1 to node N
function findShortestPath(N, M, edges) {
    // Create an adjacency list for the graph
    const adjList = Array.from({ length: N + 1 }, () => []);
    for (const [u, v] of edges) {
        adjList[u].push(v); // Add edge u -> v
        adjList[v].push(u); // Add edge v -> u (undirected graph)
    }

    // BFS setup
    const queue = [1]; // Start BFS from node 1
    const visited = new Array(N + 1).fill(false); // Track visited nodes
    const distance = new Array(N + 1).fill(Infinity); // Initialize distances to Infinity

    visited[1] = true; // Mark node 1 as visited
    distance[1] = 1; // Starting node counts as the first server in the route

    // Perform BFS
    while (queue.length > 0) {
        const node = queue.shift(); // Dequeue the front node

        // Process all neighbors of the current node
        for (const neighbor of adjList[node]) {
            if (!visited[neighbor]) {
                visited[neighbor] = true; // Mark neighbor as visited
                distance[neighbor] = distance[node] + 1; // Update distance to this neighbor
                queue.push(neighbor); // Enqueue the neighbor

                // If we've reached node N, return the distance
                if (neighbor === N) {
                    return distance[neighbor];
                }
            }
        }
    }

    // Return -1 if node N is not reachable
    return -1;
}

// Read input from standard input
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

const input = [];
rl.on('line', (line) => {
    input.push(line.trim());
});

rl.on('close', () => {
    // Parse the number of nodes (N) and edges (M)
    const [N, M] = input[0].split(' ').map(Number);

    // Parse each edge from the input
    const edges = input.slice(1).map(line => line.split(' ').map(Number));

    // Find the shortest path and print the result
    const result = findShortestPath(N, M, edges);
    console.log(result);
});
